"use strict";(self.webpackChunkopen_source_with_slu=self.webpackChunkopen_source_with_slu||[]).push([[8260],{2586:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>c,contentTitle:()=>o,default:()=>p,frontMatter:()=>s,metadata:()=>r,toc:()=>l});const r=JSON.parse('{"id":"programs/advocacy","title":"Advocacy Programs","description":"Open science and open source software represent more than just technical practices. They embody a philosophy of knowledge sharing, collaborative innovation, and equitable access that aligns deeply with Jesuit educational values. These principles drive breakthrough discoveries, amplify research impact across disciplines, and create pathways for meaningful participation in the global research enterprise. Our advocacy work champions these transformative approaches both within Saint Louis University and across the broader academic community.","source":"@site/docs/programs/advocacy.md","sourceDirName":"programs","slug":"/programs/advocacy","permalink":"/programs/advocacy","draft":false,"unlisted":false,"editUrl":null,"tags":[],"version":"current","frontMatter":{"id":"advocacy","title":"Advocacy Programs","custom_edit_url":null},"sidebar":"tutorialSidebar","previous":{"title":"Consulting Programs","permalink":"/programs/consulting"},"next":{"title":"Product Portfolio","permalink":"/projects/portfolio"}}');var a=t(4848),i=t(8453);const s={id:"advocacy",title:"Advocacy Programs",custom_edit_url:null},o=void 0,c={},l=[];function d(e){const n={a:"a",p:"p",strong:"strong",...(0,i.R)(),...e.components},{Details:t}=n;return t||function(e,n){throw new Error("Expected "+(n?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.p,{children:"Open science and open source software represent more than just technical practices. They embody a philosophy of knowledge sharing, collaborative innovation, and equitable access that aligns deeply with Jesuit educational values. These principles drive breakthrough discoveries, amplify research impact across disciplines, and create pathways for meaningful participation in the global research enterprise. Our advocacy work champions these transformative approaches both within Saint Louis University and across the broader academic community."}),"\n",(0,a.jsx)("div",{class:"affiliation-card",children:(0,a.jsx)("div",{class:"logo-container",children:(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:'"Our modern society\u2014everything from hospitals to stock markets to newspapers to social media\u2014runs on software. But take a closer look, and you\'ll find that the tools we use to build software are buckling under demand."'})," ",(0,a.jsx)("br",{}),"\n\u2014 ",(0,a.jsx)(n.a,{href:"https://www.fordfoundation.org/work/learning/research-reports/roads-and-bridges-the-unseen-labor-behind-our-digital-infrastructure/",children:'Nadia Eghbal. "Roads and Bridges: The Unseen Labor Behind Our Digital Infrastructure". 2016.'})]})})}),"\n",(0,a.jsx)("br",{}),"\n",(0,a.jsx)(n.p,{children:"When researchers share their data, code, and methodologies openly, they accelerate the pace of discovery while enabling others to build upon their work. This collaborative approach strengthens individual research projects and addresses complex global challenges that require coordinated efforts across institutions, disciplines, and borders."}),"\n",(0,a.jsxs)(t,{children:[(0,a.jsx)("summary",{children:"Internal Advocacy"}),(0,a.jsx)(n.p,{children:"Within Saint Louis University, we serve as catalysts for cultural change toward more open and collaborative research practices. Our formal recognition as a university program brings visibility and legitimacy to open science initiatives, signaling institutional commitment to these values. Through our experiential learning programs, we demonstrate tangible benefits of open approaches: students develop professionally relevant skills while creating software that serves real research needs and contributes to the global commons."}),(0,a.jsx)(n.p,{children:"Our consulting services provide another powerful advocacy tool, helping individual researchers and departments navigate the transition to open practices. By reducing barriers and providing practical support, we enable more faculty to experience firsthand the benefits of open scholarship."}),(0,a.jsx)(n.p,{children:'Educational outreach represents a cornerstone of our internal advocacy. Through workshops, seminars, and informal conversations, we help faculty, staff, and students understand not just the "how" of open science but the "why." We address common concerns about competitive disadvantage, intellectual property protection, and career implications, providing evidence-based responses that acknowledge real challenges while highlighting substantial benefits.'}),(0,a.jsx)(n.p,{children:"We also advocate through strategic partnerships with other campus units. Collaborating with the library on open access initiatives, working with technology transfer on open source licensing strategies, and partnering with graduate education on research training creates a network of support that reinforces open science messages across multiple touchpoints."})]}),"\n",(0,a.jsxs)(t,{children:[(0,a.jsx)("summary",{children:"External Advocacy"}),(0,a.jsx)(n.p,{children:"Beyond our campus, we actively participate in regional, national, and international conversations about the future of research and scholarship."}),(0,a.jsx)(n.p,{children:"Conference presentations and academic publications allow us to share our programmatic innovations with peers at other institutions. We present at venues like the Research Software Engineers Conference, FOSSY, The United Nations OSPOS for Good symposium, and disciplinary meetings to demonstrate how academic institutions can effectively support open science through structured programs and dedicated resources."}),(0,a.jsx)(n.p,{children:"We maintain active relationships with key organizations in the open science ecosystem, including the US Research Software Alliance, HELIOS Open, CURIOSS, and various open source foundations. These partnerships enable us to stay current with best practices while contributing to policy discussions that shape the future of open research infrastructure."}),(0,a.jsx)(n.p,{children:"International outreach extends our advocacy to global audiences through virtual events, collaborative projects, and cross-institutional partnerships. Saint Louis University's campus in Madrid is a key partner, engaging in the dynamic and unfolding requirements for Open Science in the European Union. Our participation in international networks helps develop more inclusive and culturally responsive approaches to open scholarship."})]}),"\n",(0,a.jsxs)(t,{children:[(0,a.jsx)("summary",{children:"Community Building"}),(0,a.jsx)(n.p,{children:"Central to all our advocacy efforts is intentional community building that creates sustainable networks of open science practitioners, especially open source software developers and research software engineers. Lasting change requires not just individual conversions but supportive communities that can maintain momentum and provide ongoing resources for open science adoption."}),(0,a.jsx)(n.p,{children:"Our Slack community serves as a hub for ongoing conversation and mutual support among researchers interested in open practices. This space facilitates peer learning, resource sharing, and collaborative problem-solving that extends far beyond any single workshop or consulting session."}),(0,a.jsx)(n.p,{children:"We organize and host networking events that bring together researchers from different disciplines and career stages who share interests in open science. These gatherings create opportunities for collaboration while building personal relationships that sustain open science communities over time."})]}),"\n",(0,a.jsxs)(t,{children:[(0,a.jsx)("summary",{children:"Measuring Impact"}),(0,a.jsx)(n.p,{children:"Our advocacy efforts are guided by systematic assessment of their effectiveness and impact. We track both quantitative metrics, such as participation in training events, adoption of recommended practices, and growth in our community networks, and qualitative indicators of cultural change within research environments."}),(0,a.jsx)(n.p,{children:"Regular surveys of faculty and students help us understand evolving attitudes toward open science, identify persistent barriers to adoption, and recognize emerging opportunities for advocacy interventions. This feedback directly informs our program development and resource allocation decisions."}),(0,a.jsx)(n.p,{children:"We document success stories and case studies that demonstrate concrete benefits of open science adoption, creating compelling narratives that support our advocacy messages. Long-term tracking of research outputs, collaboration patterns, and career outcomes for program participants helps us understand and communicate the sustained impact of open science practices."})]})]})}function p(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453:(e,n,t)=>{t.d(n,{R:()=>s,x:()=>o});var r=t(6540);const a={},i=r.createContext(a);function s(e){const n=r.useContext(i);return r.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),r.createElement(i.Provider,{value:n},e.children)}}}]);